import{_ as t,a,b as n,c as i}from"./chunks/查询额度成功的卡牌.2KCF7h3O.js";import{_ as s,o as d,c as r,a2 as l}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"S3-Kanal hinzufügen","description":"","frontmatter":{},"headers":[],"relativePath":"de-DE/upload/s3.md","filePath":"de-DE/upload/s3.md","lastUpdated":1781962217000}'),o={name:"de-DE/upload/s3.md"};function c(h,e,u,p,g,f){return d(),r("div",null,[...e[0]||(e[0]=[l(`<h1 id="s3-kanal-hinzufugen" tabindex="-1">S3-Kanal hinzufügen <a class="header-anchor" href="#s3-kanal-hinzufugen" aria-label="Permalink to &quot;S3-Kanal hinzufügen&quot;">​</a></h1><h2 id="geeignet-fur" tabindex="-1">Geeignet für <a class="header-anchor" href="#geeignet-fur" aria-label="Permalink to &quot;Geeignet für&quot;">​</a></h2><p>Nutze den S3-Kanal, wenn:</p><ul><li>du einen S3-kompatiblen Objektspeicher anbinden möchtest, etwa Cloudflare R2, Backblaze B2, MinIO, AWS S3 oder einen anderen kompatiblen Anbieter.</li><li>du das klassische S3-Konfigurationsmodell mit <code>Endpoint</code>, Access Key und Secret Key bevorzugst.</li><li>du nicht den nativen Cloudflare-R2-Binding-Kanal verwenden möchtest oder dein Anbieter nicht Cloudflare R2 ist.</li></ul><h2 id="was-du-vorher-brauchst" tabindex="-1">Was du vorher brauchst <a class="header-anchor" href="#was-du-vorher-brauchst" aria-label="Permalink to &quot;Was du vorher brauchst&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Voraussetzung</th><th>Zweck</th></tr></thead><tbody><tr><td>S3 Endpoint</td><td>API-Endpunkt des Objektspeichers.</td></tr><tr><td>Bucket-Name</td><td>Bucket, in dem Dateien gespeichert werden.</td></tr><tr><td>Region</td><td>Speicherregion. Bei Cloudflare R2 meistens <code>auto</code>.</td></tr><tr><td>Access Key ID</td><td>S3-Zugriffsschlüssel-ID.</td></tr><tr><td>Secret Access Key</td><td>Geheimer S3-Zugriffsschlüssel.</td></tr><tr><td>CDN-Domain</td><td>Optionaler eigener Zugriffsdomainname.</td></tr></tbody></table><p>Beispiel für Cloudflare R2 über die S3-API:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Endpoint: https://your-account-id.r2.cloudflarestorage.com</span></span>
<span class="line"><span>Bucket: your-r2-bucket-name</span></span>
<span class="line"><span>Region: auto</span></span>
<span class="line"><span>Access Key ID: aus dem Cloudflare-R2-API-Token kopiert</span></span>
<span class="line"><span>Secret Access Key: aus dem Cloudflare-R2-API-Token kopiert</span></span></code></pre></div><h2 id="wo-hinzufugen" tabindex="-1">Wo hinzufügen <a class="header-anchor" href="#wo-hinzufugen" aria-label="Permalink to &quot;Wo hinzufügen&quot;">​</a></h2><ol><li>Öffne die Systemeinstellungen.</li><li>Gehe zu Upload-Einstellungen.</li><li>Klicke oben rechts auf Kanal hinzufügen.</li><li>Wähle <code>S3</code>.</li></ol><h2 id="feldubersicht" tabindex="-1">Feldübersicht <a class="header-anchor" href="#feldubersicht" aria-label="Permalink to &quot;Feldübersicht&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Feld</th><th>Funktion</th><th>Erforderlich</th></tr></thead><tbody><tr><td>Kanalname</td><td>Ein gut erkennbarer Name für diesen S3-Kanal, z. B. <code>s3test</code> oder <code>R2-S3</code>.</td><td>Ja</td></tr><tr><td>Kanal aktivieren</td><td>Legt fest, ob dieser Kanal bei der Upload-Auswahl verwendet wird.</td><td>Empfohlen</td></tr><tr><td>Endpoint</td><td>Vollständiger S3-Service-Endpunkt inklusive <code>https://</code>.</td><td>Ja</td></tr><tr><td>Eigene CDN-Domain</td><td>Optional. Wenn gesetzt, bevorzugen generierte Dateilinks diese Domain.</td><td>Nein</td></tr><tr><td>Bucket-Name</td><td>Bucket-Name, z. B. <code>s3test</code> oder <code>img-r2</code>.</td><td>Ja</td></tr><tr><td>Bucket-Region</td><td>Region. Bei Cloudflare R2 meistens <code>auto</code>.</td><td>Ja</td></tr><tr><td>Access Key ID</td><td>S3-Zugriffsschlüssel-ID.</td><td>Ja</td></tr><tr><td>Secret Access Key</td><td>Geheimer S3-Zugriffsschlüssel.</td><td>Ja</td></tr><tr><td>Path-style access</td><td>Kompatibilitätsschalter. Standardmäßig aus. Manche MinIO-, OpenList- oder selbst gehostete S3-Dienste benötigen ihn.</td><td>Nein</td></tr><tr><td>Quotenlimit</td><td>Steuert, ob dieser S3-Kanal abhängig von der Kapazität bei Uploads berücksichtigt wird.</td><td>Nein</td></tr><tr><td>Kapazitätslimit</td><td>Nach Aktivierung des Quotenlimits erforderlich, z. B. <code>10 GB</code>.</td><td>Erforderlich bei aktivem Quotenlimit</td></tr><tr><td>Schwellenwert</td><td>Stoppt Schreibvorgänge nach Erreichen dieses Prozentsatzes, z. B. <code>90%</code>.</td><td>Erforderlich bei aktivem Quotenlimit</td></tr><tr><td>Bemerkung</td><td>Notizen für deine eigene Wartung.</td><td>Nein</td></tr></tbody></table><h2 id="cloudflare-r2-s3-api-schlussel-erstellen" tabindex="-1">Cloudflare-R2-S3-API-Schlüssel erstellen <a class="header-anchor" href="#cloudflare-r2-s3-api-schlussel-erstellen" aria-label="Permalink to &quot;Cloudflare-R2-S3-API-Schlüssel erstellen&quot;">​</a></h2><ol><li>Öffne das Cloudflare Dashboard.</li><li>Gehe zu <code>R2 Object Storage</code>.</li><li>Suche <code>Manage R2 API Tokens</code> oder den Eintrag zur API-Token-Verwaltung.</li></ol><p>![R2-API-Token-Einstieg](../../image/upload/s3/r2 api token入口.png)</p><ol start="4"><li>Erstelle ein R2-API-Token mit Zugriff auf den Ziel-Bucket.</li></ol><p><img src="`+t+'" alt="Account-API-Token erstellen" loading="lazy"></p><ol start="5"><li>Kopiere die erzeugten Werte <code>Access Key ID</code> und <code>Secret Access Key</code>.</li></ol><p><img src="'+a+'" alt="Token-Werte kopieren" loading="lazy"></p><ol start="6"><li>Kehre zur R2-Bucket-Seite zurück und prüfe den Bucket-Namen.</li><li>Notiere den S3-API-Endpunkt des Kontos. Er sieht normalerweise so aus:</li></ol><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>https://your-account-id.r2.cloudflarestorage.com</span></span></code></pre></div><h2 id="einrichtungsschritte" tabindex="-1">Einrichtungsschritte <a class="header-anchor" href="#einrichtungsschritte" aria-label="Permalink to &quot;Einrichtungsschritte&quot;">​</a></h2><ol><li>Öffne die Upload-Einstellungen.</li><li>Klicke auf Kanal hinzufügen.</li><li>Wähle <code>S3</code>.</li><li>Trage einen gut erkennbaren Kanalnamen ein, z. B. <code>s3test</code>.</li><li>Trage den S3-API-Endpunkt bei <code>Endpoint</code> ein.</li><li>Wenn du ein eigenes CDN nutzt, trage es bei <code>Custom CDN domain</code> ein; sonst leer lassen.</li><li>Trage den Bucket-Namen ein.</li><li>Trage die Region ein. Für Cloudflare R2 im Beispiel ist das <code>auto</code>.</li><li>Trage Access Key ID und Secret Access Key ein.</li><li>Lasse Path-style access ausgeschaltet, sofern dein Anbieter ihn nicht ausdrücklich verlangt.</li><li>Wenn du Kapazitätssteuerung möchtest, aktiviere das Quotenlimit und trage Kapazitätslimit sowie Schwellenwert ein.</li><li>Klicke auf Speichern.</li></ol><p><img src="'+n+'" alt="S3-Konfiguration hinzufügen" loading="lazy"></p><h2 id="prufung" tabindex="-1">Prüfung <a class="header-anchor" href="#prufung" aria-label="Permalink to &quot;Prüfung&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Prüfung</th><th>So prüfst du es</th></tr></thead><tbody><tr><td>Kanalkarte erscheint</td><td>Nach dem Speichern sollte in den Upload-Einstellungen eine S3-Kanalkarte sichtbar sein.</td></tr><tr><td>Kanal ist aktiv</td><td>Der Schalter oben rechts auf der Karte bleibt eingeschaltet.</td></tr><tr><td>Wichtige Felder sind gespeichert</td><td>Die Detailansicht zeigt Endpoint, Bucket, Region, Path-style access und verwandte Felder.</td></tr><tr><td>Upload funktioniert</td><td>Lade ein Testbild hoch und prüfe, ob das Objekt im Ziel-Bucket erscheint.</td></tr><tr><td>Link öffnet sich</td><td>Der nach dem Upload zurückgegebene Bildlink lässt sich normal öffnen.</td></tr><tr><td>Kapazitätsanzeige funktioniert</td><td>Bei aktivem Quotenlimit zeigt die Karte belegten Speicher und konfiguriertes Limit.</td></tr></tbody></table><p>S3-Kapazitätsstatistiken werden aus den lokalen Dateidatensätzen von ImgBed berechnet, nicht in Echtzeit aus dem Anbieter-Bucket abgefragt. Nach dem Speichern einer S3-Konfiguration berechnet das System die Quotenübersicht anhand der aktuellen D1-Einträge neu.</p><p><img src="'+i+`" alt="Quotenabfrage erfolgreich" loading="lazy"></p><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="soll-ich-path-style-access-aktivieren" tabindex="-1">Soll ich Path-style access aktivieren? <a class="header-anchor" href="#soll-ich-path-style-access-aktivieren" aria-label="Permalink to &quot;Soll ich Path-style access aktivieren?&quot;">​</a></h3><p>In der Regel nein.</p><p>Aktiviere ihn nur, wenn dein S3-kompatibler Anbieter keine Virtual-hosted-style-URLs unterstützt oder die Dokumentation des Anbieters Path-style access ausdrücklich verlangt. Manche MinIO-, selbst gehostete S3- und OpenList-kompatible Endpunkte benötigen das.</p><h3 id="wofur-ist-die-cdn-domain" tabindex="-1">Wofür ist die CDN-Domain? <a class="header-anchor" href="#wofur-ist-die-cdn-domain" aria-label="Permalink to &quot;Wofür ist die CDN-Domain?&quot;">​</a></h3><p>Wenn du ein CDN oder eine eigene Zugriffsdomain vor den Bucket schaltest, trägst du sie hier ein.</p><p>Nach der Konfiguration bevorzugt ImgBed diese Domain für generierte Dateilinks. Wenn du kein CDN nutzt, lässt du das Feld leer.</p><h3 id="warum-schlagt-der-upload-fehl" tabindex="-1">Warum schlägt der Upload fehl? <a class="header-anchor" href="#warum-schlagt-der-upload-fehl" aria-label="Permalink to &quot;Warum schlägt der Upload fehl?&quot;">​</a></h3><p>Prüfe zuerst diese Punkte:</p><ol><li>Der Endpoint enthält die vollständige <code>https://</code>-URL.</li><li>Der Bucket-Name stimmt.</li><li>Die Region passt zu den Vorgaben des Anbieters.</li><li>Access Key ID und Secret Access Key wurden vollständig kopiert.</li><li>Der Schlüssel hat Schreibrechte für den Ziel-Bucket.</li><li>Der Anbieter benötigt keinen Path-style access, oder er wurde aktiviert, falls nötig.</li></ol><h2 id="kurzcheck" tabindex="-1">Kurzcheck <a class="header-anchor" href="#kurzcheck" aria-label="Permalink to &quot;Kurzcheck&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>S3 Endpoint, Bucket, Region, Access Key und Secret Key vorbereiten</span></span>
<span class="line"><span>-&gt; Upload-Einstellungen öffnen</span></span>
<span class="line"><span>-&gt; Kanal hinzufügen</span></span>
<span class="line"><span>-&gt; S3 wählen</span></span>
<span class="line"><span>-&gt; Endpoint / Bucket / Region / Access Key / Secret Key eintragen</span></span>
<span class="line"><span>-&gt; Bei Bedarf CDN-Domain eintragen</span></span>
<span class="line"><span>-&gt; Path-style access standardmäßig ausgeschaltet lassen</span></span>
<span class="line"><span>-&gt; Bei Bedarf Quotenlimit aktivieren</span></span>
<span class="line"><span>-&gt; Speichern</span></span>
<span class="line"><span>-&gt; Testbild hochladen und Ergebnis prüfen</span></span></code></pre></div>`,40)])])}const S=s(o,[["render",c]]);export{m as __pageData,S as default};
